from flask import Flask, request, jsonify
import face_recognition
import numpy as np
import os
import json

app = Flask(__name__)

# Load employee photos and encode faces
employee_encodings = {}
employee_names = []

def load_employee_data(directory):
    for filename in os.listdir(directory):
        if filename.endswith(".jpg") or filename.endswith(".png"):
            image_path = os.path.join(directory, filename)
            image = face_recognition.load_image_file(image_path)
            encoding = face_recognition.face_encodings(image)
            if encoding:
                employee_encodings[filename.split('.')[0]] = encoding[0]
                employee_names.append(filename.split('.')[0])

load_employee_data('employee_photos')

@app.route('/recognize', methods=['POST'])
def recognize_face():
    if 'image' not in request.files:
        return jsonify({'error': 'No image provided'}), 400

    file = request.files['image']
    image = face_recognition.load_image_file(file)
    face_encodings = face_recognition.face_encodings(image)

    if not face_encodings:
        return jsonify({'error': 'No face found in the image'}), 400

    face_encoding = face_encodings[0]
    distances = face_recognition.face_distance(list(employee_encodings.values()), face_encoding)
    probabilities = np.exp(-distances) / np.sum(np.exp(-distances))

    response = {name: float(prob) for name, prob in zip(employee_names, probabilities)}
    return jsonify(response)

if __name__ == '__main__':
    app.run(host='0.0.0.0', port=5000, debug=False)